def _compile_floor13_k80_kernels() -> dict[str, Any]:
    return _decode_capture(_json_loads('{"merge": {"__kernel__": "dispatch_kernel_0462"}, "partial": {"__kernel__": "dispatch_kernel_0461"}}'))

def _ensure_kernels() -> dict[str, Any]:
    if not _KNN_SEARCH_FLOOR13_K80_KERNELS:
        _KNN_SEARCH_FLOOR13_K80_KERNELS.update(_compile_floor13_k80_kernels())
    return _KNN_SEARCH_FLOOR13_K80_KERNELS

def _partial_scratch(inputs: dict[str, Any], partial_list_count: int, num_q_tiles: int) -> tuple[Any, Any]:
    import torch
    key = (int(inputs['B']), int(inputs['Q']), int(inputs['M']), int(partial_list_count), int(num_q_tiles), LOCAL_PREFIX_K, int(inputs['queries'].device.index or 0), str(inputs['queries'].dtype))
    cached = _KNN_SEARCH_FLOOR13_K80_SCRATCH.get(key)
    if cached is None:
        shape = (int(inputs['B']), int(num_q_tiles), int(partial_list_count), BLOCK_Q, LOCAL_PREFIX_K)
        cached = (torch.empty(shape, dtype=torch.float32, device=inputs['queries'].device), torch.empty(shape, dtype=torch.int32, device=inputs['queries'].device))
        _KNN_SEARCH_FLOOR13_K80_SCRATCH[key] = cached
    return cached

def supports_floor13_k80_prefix8(inputs: dict[str, Any]) -> bool:
    bsz = int(inputs.get('B', 1))
    q_rows = int(inputs['Q'])
    m_rows = int(inputs['M'])
    return not bool(inputs.get('force_fallback', False)) and bsz == 1 and (int(inputs['D']) == D_STATIC) and (int(inputs['K']) == K80_MAX) and (not bool(inputs.get('self_search', False))) and k64_parent.base._tcgen05_capable_arch() and (q_rows == 128 and m_rows == 65536 or (q_rows == 4096 and m_rows == 32768))

def _launch_floor13_k80_prefix8(inputs: dict[str, Any]) -> dict[str, Any]:
    import torch
    kernels = _ensure_kernels()
    bsz = int(inputs['B'])
    q_rows = int(inputs['Q'])
    m_rows = int(inputs['M'])
    k = int(inputs['K'])
    num_q_tiles = math.ceil(q_rows / BLOCK_Q)
    total_m_tiles = math.ceil(m_rows / BLOCK_M)
    if total_m_tiles % 2 != 0:
        raise ValueError('floor13 K80 prefix8 route requires an even number of M128 tiles')
    split_m = total_m_tiles // 2
    tiles_per_split = 2
    partial_list_count = split_m * MMA_POST_MMA_COL_COHORTS
    partial_dist, partial_idx = _partial_scratch(inputs, partial_list_count, num_q_tiles)
    kernels['partial'].launch(grid=(bsz * num_q_tiles * split_m, 1, 1), block=(THREADS, 1, 1), args=[inputs['queries'], inputs['database'], partial_dist, partial_idx, bsz, q_rows, m_rows, split_m, num_q_tiles, total_m_tiles, tiles_per_split, partial_list_count], shared_mem=MMA_SMEM_BYTES)
    kernels['merge'].launch(grid=(bsz * q_rows, 1, 1), block=(MERGE_THREADS, 1, 1), args=[partial_dist, partial_idx, inputs['out_distances'], inputs['out_indices'], bsz, q_rows, k, partial_list_count, num_q_tiles], shared_mem=MERGE_SMEM_BYTES)
    return {'distances': inputs['out_distances'], 'indices': inputs['out_indices']}

def selected_route_name(inputs: dict[str, Any]) -> str:
    if supports_floor13_k80_prefix8(inputs):
        return ROUTE_FLOOR13_K80_PREFIX8
    return k64_parent.selected_route_name(inputs)

def selected_route(inputs: dict[str, Any]) -> str:
    return selected_route_name(inputs)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    route = selected_route_name(inputs)
    if route == ROUTE_FLOOR13_K80_PREFIX8:
        parent_info = dict(k64_parent.route_info(inputs))
        parent_route = parent_info.get('route') or parent_info.get('selected_route')
        m_rows = int(inputs['M'])
        partial_list_count = math.ceil(m_rows / BLOCK_M) // 2 * MMA_POST_MMA_COL_COHORTS
        return {'route': route, 'selected_route': route, 'selected_entrypoint': _FLOOR13_K80_ENTRY['entrypoint'], 'parent_route': parent_route, 'replaced_route': parent_route, 'route_kind': 'specialized', 'route_source': 'shape-specific-seed', 'coverage_class': 'floor13_k80_prefix8', 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': [entry['shape_key'] for entry in SHAPE_DISPATCH_REGISTRY], 'forced_fallback': False, 'selected_guard': _FLOOR13_K80_ENTRY['guard'], 'fallback': parent_route, 'split_m': partial_list_count // MMA_POST_MMA_COL_COHORTS, 'partial_lists': partial_list_count, 'local_prefix_k': LOCAL_PREFIX_K, 'source_task': _FLOOR13_K80_ENTRY['source_task'], 'selected_seed': _FLOOR13_K80_ENTRY['selected_seed']}
    info = dict(k64_parent.route_info(inputs))
    info['route'] = route
    info['selected_route'] = route
    info['guard_order'] = [entry['shape_key'] for entry in SHAPE_DISPATCH_REGISTRY]
    return info

def route_trace_entry(label: str, inputs: dict[str, Any]) -> dict[str, Any]:
    return {'label': label, 'shape_key': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), 'self_search': bool(inputs.get('self_search', False)), **route_info(inputs)}

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    if supports_floor13_k80_prefix8(inputs):
        return _launch_floor13_k80_prefix8(inputs)
    return k64_parent.launch_for_eval(inputs)

def knn_search_compile_and_launch_floor13_k80_prefix8(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=TARGET_SHAPES if shapes is None else shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result
